def compute_plan(desired, current):
    desired_set = set(desired)
    current_set = set(current)
    return {
        "create": sorted(desired_set - current_set),
        "keep": sorted(desired_set & current_set),
        "destroy": sorted(current_set - desired_set),
    }

def apply_plan(current, plan):
    state = set(current)
    state.update(plan["create"])
    state.difference_update(plan["destroy"])
    return sorted(state)

def run_once(desired, current):
    plan = compute_plan(desired, current)
    return {"plan": plan, "state": apply_plan(current, plan)}

def compute_plan(desired, current):
    d, c = set(desired), set(current)
    return {"create": sorted(d - c), "keep": sorted(d & c), "destroy": sorted(c - d)}

def apply_plan(current, plan):
    return sorted((set(current) | set(plan["create"])) - set(plan["destroy"]))

def run_once(desired, current):
    plan = compute_plan(desired, current)
    return {"plan": plan, "state": apply_plan(current, plan)}
